import { auth } from "@/lib/auth";
import { NextResponse } from "next/server";
import type { NextRequest } from "next/server";

export default auth((req) => {
  const isLoggedIn = !!req.auth;
  const { nextUrl } = req;
  const user = req.auth?.user as any;

  // 1. If not logged in and not on login page, redirect to login
  if (!isLoggedIn && nextUrl.pathname !== "/login" && !nextUrl.pathname.startsWith("/api/auth")) {
    return NextResponse.redirect(new URL("/login", nextUrl));
  }

  // 2. Role-based protection
  if (isLoggedIn) {
    // Super Admin access
    if (nextUrl.pathname.startsWith("/super-admin") && user.role !== "SUPER_ADMIN") {
      return NextResponse.redirect(new URL("/dashboard", nextUrl));
    }

    // Owner/Manager/Cashier access to store dashboard
    if (nextUrl.pathname.startsWith("/dashboard") && !["OWNER", "MANAGER", "CASHIER", "SUPER_ADMIN"].includes(user.role)) {
      return NextResponse.redirect(new URL("/login", nextUrl));
    }
  }

  return NextResponse.next();
});

export const config = {
  matcher: ["/((?!api|_next/static|_next/image|favicon.ico).*)"],
};
